import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.Files;
import java.io.IOException;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String directoryPath = "/path/to/files/";

        // Securely resolve the file path
        Path resolvedPath = Paths.get(directoryPath).resolve(userInput).normalize();

        if (resolvedPath.startsWith(Paths.get(directoryPath))) {
            try {
                byte[] fileContent = Files.readAllBytes(resolvedPath);
                System.out.println(new String(fileContent));
            } catch (IOException e) {
                System.err.println("Error reading file");
            }
        } else {
            System.out.println("Access to file outside directory is not allowed");
        }
    }
}

